// Parse Claude response and filter low confidence
const body = $input.item.json;
let raw = '';
try {
  raw = body.content[0].text || '';
} catch(e) { raw = JSON.stringify(body); }

let ai = {};
try {
  const clean = raw.replace(/```json/gi,'').replace(/```/g,'').trim();
  ai = JSON.parse(clean);
} catch(e) {
  const m = raw.match(/\{[\s\S]*\}/);
  try { ai = JSON.parse(m ? m[0] : '{}'); } catch(e2) { ai = {}; }
}

const base = $('STEP 6 - Combine Search Results').item.json;

// Drop LOW confidence fields
const domain = (ai.domain_confidence === 'LOW') ? '' : (ai.domain || '');
const ownerName = (ai.owner_confidence === 'LOW' || ai.owner_confidence === 'NOT_FOUND') ? '' : (ai.owner_name || '');
const directorName = (ai.director_confidence === 'LOW' || ai.director_confidence === 'NOT_FOUND') ? '' : (ai.director_name || '');
const phones = (ai.phones || []).filter(p => p && p.length > 5).join(' | ');
const searchEmails = (ai.emails_from_search || []).filter(Boolean);

return {
  row_number: base.row_number,
  company_name: base.company_name,
  country: base.country,
  domain: domain,
  domain_confidence: ai.domain_confidence || 'NOT_FOUND',
  website_url: ai.website_url || '',
  company_official_name: ai.company_official_name || base.company_name,
  company_description: ai.company_description || '',
  owner_name: ownerName,
  owner_confidence: ai.owner_confidence || 'NOT_FOUND',
  owner_linkedin: ai.owner_linkedin || '',
  director_name: directorName,
  director_confidence: ai.director_confidence || 'NOT_FOUND',
  ceo_name: ai.ceo_name || '',
  founder_name: ai.founder_name || '',
  phones: phones,
  emails_from_search: searchEmails,
  linkedin_company_url: ai.linkedin_company_url || '',
  overall_confidence: ai.overall_confidence || 0,
  notes: ai.notes || '',
  snov_domain: domain
};

// Check domain live status
const resp = $input.item.json;
const status = resp.$response?.statusCode || resp.statusCode || 0;
const isLive = status >= 200 && status < 500;
const base = $('STEP 8 - Parse AI Response').item.json;

return {
  ...base,
  domain_is_live: isLive,
  domain_http_status: status
};

// Parse Snov.io domain emails
const snovResp = $input.item.json;
const base = $('STEP 8 - Parse AI Response').item.json;

let emails = [];
if (Array.isArray(snovResp.emails)) {
  emails = snovResp.emails.map(e => typeof e === 'string' ? e : e.email).filter(Boolean);
} else if (Array.isArray(snovResp.data)) {
  emails = snovResp.data.map(e => typeof e === 'string' ? e : e.email).filter(Boolean);
} else if (Array.isArray(snovResp)) {
  emails = snovResp.map(e => typeof e === 'string' ? e : e.email).filter(Boolean);
}

// Merge with search emails
const searchEmails = base.emails_from_search || [];
const allUnique = [...new Set([...emails, ...searchEmails])];

return {
  ...base,
  snov_emails: allUnique
};

// No domain path - use only search emails
const base = $('STEP 8 - Parse AI Response').item.json;
return {
  ...base,
  domain_is_live: false,
  domain_http_status: 0,
  snov_emails: base.emails_from_search || []
};

// FINAL ASSEMBLY - Build complete verified output
// Get domain live data
let domainBase = {};
try { domainBase = $('STEP 11A - Domain Live Result').item.json; } catch(e) {}
try { if (!domainBase.row_number) domainBase = $('STEP 10C - No Domain Path').item.json; } catch(e) {}

// Get snov emails + verification
let snovEmails = [];
try { snovEmails = $('STEP 11B - Process Snov Emails').item.json.snov_emails || []; } catch(e) {}
try { if (!snovEmails.length) snovEmails = $('STEP 10C - No Domain Path').item.json.snov_emails || []; } catch(e) {}

// Get verification result
let verifiedSet = new Set();
let unverifiedList = [];
try {
  const vr = $('STEP 12 - Snov Verify Emails').item.json;
  const vdata = vr.data || vr.emails || vr || [];
  if (Array.isArray(vdata)) {
    vdata.forEach(r => {
      const em = r.email || r;
      const st = (r.status || r.result || '').toLowerCase();
      if (['valid','verified','deliverable'].includes(st)) verifiedSet.add(em);
      else if (!['invalid','catch_all_invalid','undeliverable'].includes(st)) unverifiedList.push(em);
    });
  }
} catch(e) { unverifiedList = snovEmails; }

const allEmails = snovEmails;
if (verifiedSet.size === 0) allEmails.forEach(e => unverifiedList.push(e));

const verifiedEmails = [...verifiedSet];
const genericPfx = ['info','contact','hello','support','sales','admin','office','mail','enquiry','hr','noreply'];
const personalVerified = verifiedEmails.filter(e => !genericPfx.some(p => e.toLowerCase().startsWith(p+'@')));
const genericVerified = verifiedEmails.filter(e => genericPfx.some(p => e.toLowerCase().startsWith(p+'@')));

const base = domainBase;

return {
  row_number: base.row_number,
  Status: 'Done',
  Domain: base.domain || '',
  Domain_Verified: base.domain_is_live ? 'YES' : 'NO',
  Website_URL: base.website_url || (base.domain ? 'https://' + base.domain : ''),
  Company_Full_Name: base.company_official_name || base.company_name,
  Company_Description: base.company_description || '',
  Owner_Name: base.owner_name || '',
  Owner_Confidence: base.owner_confidence || '',
  Owner_LinkedIn: base.owner_linkedin || '',
  Director_Name: base.director_name || '',
  CEO_Name: base.ceo_name || '',
  Founder_Name: base.founder_name || '',
  Verified_Emails: verifiedEmails.join(' | '),
  Personal_Emails: personalVerified.join(' | '),
  Generic_Emails: genericVerified.join(' | '),
  Unverified_Emails: unverifiedList.slice(0,10).join(' | '),
  Total_Emails_Found: allEmails.length,
  Phone_Numbers: base.phones || '',
  LinkedIn_Company: base.linkedin_company_url || '',
  Overall_Confidence: base.overall_confidence || 0,
  Research_Notes: base.notes || '',
  Last_Updated: new Date().toISOString()
};
